import { Question } from "@/lib/types";

export const questions: Question[] = [
    // ── Sample space, equally likely outcomes, complementary events ────
    { id: "y1pr1-001", topicRef: "y1pr1", topicTitle: "Probability 01", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["sample space", "equally likely"], questionText: "A fair six-sided die is rolled once. Find the probability that the score is (a) a 4, (b) an even number.", workedSolution: { steps: [{ stepNumber: 1, description: "Sample space.", workingLatex: "S = \\{1,2,3,4,5,6\\}, \\ n(S) = 6.", explanation: "" }, { stepNumber: 2, description: "Probability of a 4.", workingLatex: "P(4) = \\tfrac{1}{6}.", explanation: "" }, { stepNumber: 3, description: "Probability of an even number.", workingLatex: "P(\\text{even}) = \\tfrac{3}{6} = \\tfrac{1}{2}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{1}{6}\\). (b) \\(\\tfrac{1}{2}\\)." } },
    { id: "y1pr1-002", topicRef: "y1pr1", topicTitle: "Probability 02", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["complement", "complementary events"], questionText: "The probability that it rains tomorrow is \\(0.42\\). Find the probability that it does not rain tomorrow.", workedSolution: { steps: [{ stepNumber: 1, description: "Use the complement.", workingLatex: "P(\\text{not rain}) = 1 - P(\\text{rain}).", explanation: "" }, { stepNumber: 2, description: "Substitute and simplify.", workingLatex: "P(\\text{not rain}) = 1 - 0.42 = 0.58.", explanation: "" }], finalAnswer: "\\(0.58\\)." } },
    { id: "y1pr1-003", topicRef: "y1pr1", topicTitle: "Probability 03", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["sample space", "two dice"], questionText: "Two fair six-sided dice are rolled. Find the probability that the total is 7.", workedSolution: { steps: [{ stepNumber: 1, description: "Total outcomes.", workingLatex: "n(S) = 6 \\times 6 = 36.", explanation: "" }, { stepNumber: 2, description: "List outcomes giving 7.", workingLatex: "(1,6),(2,5),(3,4),(4,3),(5,2),(6,1) \\Rightarrow 6 \\text{ outcomes.}", explanation: "" }, { stepNumber: 3, description: "Compute probability.", workingLatex: "P(\\text{total}=7) = \\tfrac{6}{36} = \\tfrac{1}{6}.", explanation: "" }], finalAnswer: "\\(\\tfrac{6}{36} = \\tfrac{1}{6}\\)." } },
    { id: "y1pr1-004", topicRef: "y1pr1", topicTitle: "Probability 04", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["sample space", "complement", "two dice"], questionText: "Two fair six-sided dice are rolled and the scores are added. Find the probability that the total is (a) 11, (b) at least 4.", workedSolution: { steps: [{ stepNumber: 1, description: "Total outcomes.", workingLatex: "n(S) = 36.", explanation: "" }, { stepNumber: 2, description: "Outcomes giving total 11.", workingLatex: "(5,6),(6,5) \\Rightarrow 2 \\text{ outcomes}, \\ P = \\tfrac{2}{36} = \\tfrac{1}{18}.", explanation: "" }, { stepNumber: 3, description: "Use the complement for at least 4.", workingLatex: "P(\\text{total} \\le 3) = P(2) + P(3) = \\tfrac{1}{36} + \\tfrac{2}{36} = \\tfrac{3}{36}.", explanation: "" }, { stepNumber: 4, description: "Subtract from 1.", workingLatex: "P(\\text{total} \\ge 4) = 1 - \\tfrac{3}{36} = \\tfrac{33}{36} = \\tfrac{11}{12}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{2}{36} = \\tfrac{1}{18}\\). (b) \\(\\tfrac{33}{36} = \\tfrac{11}{12}\\)." } },
    { id: "y1pr1-005", topicRef: "y1pr1", topicTitle: "Probability 05", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["sample space", "cards"], questionText: "A card is drawn at random from a standard pack of 52 playing cards. Find the probability that the card is (a) a club, (b) a face card (jack, queen, king), (c) a club or a face card.", workedSolution: { steps: [{ stepNumber: 1, description: "P(club).", workingLatex: "P(\\text{club}) = \\tfrac{13}{52} = \\tfrac{1}{4}.", explanation: "" }, { stepNumber: 2, description: "P(face card).", workingLatex: "P(\\text{face}) = \\tfrac{12}{52} = \\tfrac{3}{13}.", explanation: "" }, { stepNumber: 3, description: "Use addition with overlap.", workingLatex: "P(\\text{club} \\cup \\text{face}) = \\tfrac{13}{52} + \\tfrac{12}{52} - \\tfrac{3}{52} = \\tfrac{22}{52} = \\tfrac{11}{26}.", explanation: "Three face cards are also clubs (J♣, Q♣, K♣)." }], finalAnswer: "(a) \\(\\tfrac{13}{52} = \\tfrac{1}{4}\\). (b) \\(\\tfrac{12}{52} = \\tfrac{3}{13}\\). (c) \\(\\tfrac{22}{52} = \\tfrac{11}{26}\\)." } },

    // ── Two-way tables ────
    { id: "y1pr1-006", topicRef: "y1pr1", topicTitle: "Probability 06", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["two-way table"], questionText: "In a class of 30 pupils, 18 study French and 14 study German; 6 study both. (a) How many study neither? (b) Find the probability a randomly chosen pupil studies French only.", workedSolution: { steps: [{ stepNumber: 1, description: "French only.", workingLatex: "18 - 6 = 12.", explanation: "" }, { stepNumber: 2, description: "German only.", workingLatex: "14 - 6 = 8.", explanation: "" }, { stepNumber: 3, description: "Neither.", workingLatex: "30 - (12 + 6 + 8) = 30 - 26 = 4.", explanation: "" }, { stepNumber: 4, description: "P(French only).", workingLatex: "P = \\tfrac{12}{30} = \\tfrac{2}{5}.", explanation: "" }], finalAnswer: "(a) 4. (b) \\(\\tfrac{12}{30} = \\tfrac{2}{5}\\)." } },
    { id: "y1pr1-007", topicRef: "y1pr1", topicTitle: "Probability 07", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["two-way table"], questionText: "A survey of 200 commuters records mode of transport (Bus or Train) and gender. \\(\\;\\) Female Bus: 48; Female Train: 52; Male Bus: 36; Male Train: 64. Find the probability that a randomly chosen commuter is (a) male, (b) female and travels by train, (c) travels by bus.", workedSolution: { steps: [{ stepNumber: 1, description: "Row totals.", workingLatex: "\\text{Female: } 48+52=100; \\ \\text{Male: } 36+64=100.", explanation: "" }, { stepNumber: 2, description: "Column totals.", workingLatex: "\\text{Bus: } 48+36=84; \\ \\text{Train: } 52+64=116.", explanation: "" }, { stepNumber: 3, description: "P(male).", workingLatex: "\\tfrac{100}{200} = 0.5.", explanation: "" }, { stepNumber: 4, description: "P(female and train).", workingLatex: "\\tfrac{52}{200} = 0.26.", explanation: "" }, { stepNumber: 5, description: "P(bus).", workingLatex: "\\tfrac{84}{200} = 0.42.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{100}{200} = 0.5\\). (b) \\(\\tfrac{52}{200} = 0.26\\). (c) \\(\\tfrac{84}{200} = 0.42\\)." } },
    { id: "y1pr1-008", topicRef: "y1pr1", topicTitle: "Probability 08", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["two-way table", "union"], questionText: "A class of 60 pupils is surveyed: 35 own a bike, 28 own a skateboard, 12 own both. A pupil is chosen at random. Find the probability that the pupil owns (a) a bike or a skateboard (or both), (b) neither.", workedSolution: { steps: [{ stepNumber: 1, description: "Use addition with overlap.", workingLatex: "P(B \\cup S) = \\tfrac{35}{60} + \\tfrac{28}{60} - \\tfrac{12}{60} = \\tfrac{51}{60}.", explanation: "" }, { stepNumber: 2, description: "Simplify.", workingLatex: "\\tfrac{51}{60} = \\tfrac{17}{20}.", explanation: "" }, { stepNumber: 3, description: "Complement for neither.", workingLatex: "P(\\text{neither}) = 1 - \\tfrac{17}{20} = \\tfrac{3}{20}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{51}{60} = \\tfrac{17}{20}\\). (b) \\(\\tfrac{9}{60} = \\tfrac{3}{20}\\)." } },
    { id: "y1pr1-009", topicRef: "y1pr1", topicTitle: "Probability 09", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["two-way table", "complement"], questionText: "A garage records 80 cars: 50 are petrol, 30 are diesel; 32 are saloons and 48 are hatchbacks. 18 of the petrol cars are saloons. A car is chosen at random. Find (a) the probability it is a diesel hatchback, (b) the probability it is petrol or a saloon.", workedSolution: { steps: [{ stepNumber: 1, description: "Fill the table.", workingLatex: "\\text{Petrol saloon } 18, \\text{ Petrol hatch } 50-18=32.", explanation: "" }, { stepNumber: 2, description: "Diesel rows.", workingLatex: "\\text{Diesel saloon } 32-18=14, \\text{ Diesel hatch } 30-14=16.", explanation: "" }, { stepNumber: 3, description: "P(diesel hatch).", workingLatex: "\\tfrac{16}{80} = 0.2.", explanation: "" }, { stepNumber: 4, description: "P(petrol or saloon).", workingLatex: "\\tfrac{50+32-18}{80} = \\tfrac{64}{80} = 0.8.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{16}{80} = 0.2\\). (b) \\(\\tfrac{64}{80} = 0.8\\)." } },
    { id: "y1pr1-010", topicRef: "y1pr1", topicTitle: "Probability 10", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["two-way table", "algebraic", "unknown"], questionText: "A school of 240 pupils is surveyed: \\(x\\) study Spanish, 90 study Latin, and 28 study both. The number who study neither is twice the number who study only Spanish. Find \\(x\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Spanish only.", workingLatex: "\\text{Spanish only} = x - 28.", explanation: "" }, { stepNumber: 2, description: "Latin only.", workingLatex: "\\text{Latin only} = 90 - 28 = 62.", explanation: "" }, { stepNumber: 3, description: "Total in terms of } x.", workingLatex: "240 = (x-28) + 28 + 62 + 2(x-28).", explanation: "" }, { stepNumber: 4, description: "Simplify.", workingLatex: "240 = 3x - 56 + 90 = 3x + 6.", explanation: "Combining: x − 28 + 28 + 62 + 2x − 56 = 3x − 56 + 90 = 3x + 6." }, { stepNumber: 5, description: "Wait check.", workingLatex: "240 = (x-28) + 28 + 62 + 2(x-28) = (x - 28 + 28) + 62 + (2x - 56) = x + 62 + 2x - 56 = 3x + 6.", explanation: "" }, { stepNumber: 6, description: "Solve.", workingLatex: "3x + 6 = 240 \\Rightarrow 3x = 234 \\Rightarrow x = 78.", explanation: "" }], finalAnswer: "\\(x = 78\\)." } },

    // ── Venn diagrams ────
    { id: "y1pr1-011", topicRef: "y1pr1", topicTitle: "Probability 11", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["Venn diagram"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.5, \\ P(B) = 0.4, \\ P(A \\cap B) = 0.2\\). Find \\(P(A \\cup B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use the addition rule.", workingLatex: "P(A \\cup B) = P(A) + P(B) - P(A \\cap B).", explanation: "" }, { stepNumber: 2, description: "Substitute.", workingLatex: "= 0.5 + 0.4 - 0.2 = 0.7.", explanation: "" }], finalAnswer: "\\(0.7\\)." } },
    { id: "y1pr1-012", topicRef: "y1pr1", topicTitle: "Probability 12", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["Venn diagram", "complement"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.6, \\ P(B) = 0.5, \\ P(A \\cup B) = 0.8\\). Find \\(P(A \\cap B)\\) and \\(P(A' \\cap B')\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Apply addition rule.", workingLatex: "0.8 = 0.6 + 0.5 - P(A \\cap B).", explanation: "" }, { stepNumber: 2, description: "Solve for intersection.", workingLatex: "P(A \\cap B) = 1.1 - 0.8 = 0.3.", explanation: "" }, { stepNumber: 3, description: "Use complement.", workingLatex: "P(A' \\cap B') = 1 - P(A \\cup B) = 1 - 0.8 = 0.2.", explanation: "" }], finalAnswer: "\\(P(A \\cap B) = 0.3\\); \\(P(A' \\cap B') = 0.2\\)." } },
    { id: "y1pr1-013", topicRef: "y1pr1", topicTitle: "Probability 13", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Venn diagram", "regions"], questionText: "In a survey of 50 students, 28 study Maths (M), 22 study Physics (P), and 10 study both. (a) Draw a Venn diagram (or describe the regions) and state how many study neither. A student is chosen at random; find (b) \\(P(M \\cap P')\\) and (c) \\(P(M' \\cap P')\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Maths only.", workingLatex: "28 - 10 = 18.", explanation: "" }, { stepNumber: 2, description: "Physics only.", workingLatex: "22 - 10 = 12.", explanation: "" }, { stepNumber: 3, description: "Neither.", workingLatex: "50 - (18 + 10 + 12) = 10.", explanation: "" }, { stepNumber: 4, description: "P(Maths only).", workingLatex: "\\tfrac{18}{50} = 0.36.", explanation: "" }, { stepNumber: 5, description: "P(neither).", workingLatex: "\\tfrac{10}{50} = 0.2.", explanation: "" }], finalAnswer: "(a) Maths only \\(=18\\), Physics only \\(=12\\), Both \\(=10\\), Neither \\(=10\\). (b) \\(\\tfrac{18}{50} = 0.36\\). (c) \\(\\tfrac{10}{50} = 0.2\\)." } },
    { id: "y1pr1-014", topicRef: "y1pr1", topicTitle: "Probability 14", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Venn diagram", "three sets"], questionText: "Of 100 sixth-formers, 60 study Maths (M), 45 study Further Maths (F), 40 study Physics (P). 30 study M and F, 25 study M and P, 20 study F and P, and 15 study all three. Find the number who study at least one of these three subjects.", workedSolution: { steps: [{ stepNumber: 1, description: "Apply inclusion–exclusion.", workingLatex: "|M \\cup F \\cup P| = |M| + |F| + |P| - |M \\cap F| - |M \\cap P| - |F \\cap P| + |M \\cap F \\cap P|.", explanation: "" }, { stepNumber: 2, description: "Substitute.", workingLatex: "= 60 + 45 + 40 - 30 - 25 - 20 + 15.", explanation: "" }, { stepNumber: 3, description: "Compute.", workingLatex: "= 145 - 75 + 15 = 85.", explanation: "" }], finalAnswer: "85." } },
    { id: "y1pr1-015", topicRef: "y1pr1", topicTitle: "Probability 15", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Venn diagram", "regions", "context"], questionText: "A class of 40 students is surveyed about whether they like coffee (C) or tea (T). 24 like coffee, 18 like tea, 8 like both. A student is chosen at random. Find (a) \\(P(C \\cup T)\\), (b) \\(P(C' \\cap T)\\), (c) \\(P(\\text{exactly one of C and T})\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Coffee only, tea only.", workingLatex: "C\\text{ only}=24-8=16, \\ T\\text{ only}=18-8=10.", explanation: "" }, { stepNumber: 2, description: "P(C \\cup T).", workingLatex: "\\tfrac{16+8+10}{40} = \\tfrac{34}{40}=0.85.", explanation: "" }, { stepNumber: 3, description: "P(C' \\cap T) = T only.", workingLatex: "\\tfrac{10}{40}=0.25.", explanation: "" }, { stepNumber: 4, description: "Exactly one.", workingLatex: "\\tfrac{16+10}{40} = \\tfrac{26}{40} = 0.65.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{34}{40} = 0.85\\). (b) \\(\\tfrac{10}{40} = 0.25\\). (c) \\(\\tfrac{26}{40} = 0.65\\)." } },
    { id: "y1pr1-016", topicRef: "y1pr1", topicTitle: "Probability 16", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["Venn diagram", "algebra", "unknown"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.5, \\ P(B) = x, \\ P(A \\cap B) = 0.2, \\ P(A' \\cap B') = 0.1\\). Find \\(x\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use complement.", workingLatex: "P(A \\cup B) = 1 - P(A' \\cap B') = 1 - 0.1 = 0.9.", explanation: "" }, { stepNumber: 2, description: "Apply addition rule.", workingLatex: "0.9 = 0.5 + x - 0.2.", explanation: "" }, { stepNumber: 3, description: "Solve.", workingLatex: "x = 0.9 - 0.3 = 0.6.", explanation: "" }], finalAnswer: "\\(x = 0.6\\)." } },
    { id: "y1pr1-017", topicRef: "y1pr1", topicTitle: "Probability 17", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["Venn diagram", "three sets", "context"], questionText: "A leisure centre offers Swimming (S), Tennis (T), and Yoga (Y). Of 80 members surveyed: 40 do S, 30 do T, 35 do Y; 12 do both S and T, 15 do both S and Y, 10 do both T and Y, and 5 do all three. Find the probability that a randomly chosen member does (a) at least one activity, (b) exactly one activity.", workedSolution: { steps: [{ stepNumber: 1, description: "Inclusion–exclusion.", workingLatex: "|S \\cup T \\cup Y| = 40+30+35-12-15-10+5 = 73.", explanation: "" }, { stepNumber: 2, description: "P(at least one).", workingLatex: "\\tfrac{73}{80}.", explanation: "" }, { stepNumber: 3, description: "Exactly one in S (only S).", workingLatex: "|S| - |S \\cap T| - |S \\cap Y| + |S \\cap T \\cap Y| = 40 - 12 - 15 + 5 = 18.", explanation: "" }, { stepNumber: 4, description: "Exactly one in T (only T).", workingLatex: "30 - 12 - 10 + 5 = 13.", explanation: "" }, { stepNumber: 5, description: "Exactly one in Y (only Y).", workingLatex: "35 - 15 - 10 + 5 = 15.", explanation: "" }, { stepNumber: 6, description: "Sum the three ‘only' regions.", workingLatex: "18 + 13 + 15 = 46.", explanation: "" }, { stepNumber: 7, description: "P(exactly one).", workingLatex: "\\tfrac{46}{80} = \\tfrac{23}{40}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{73}{80}\\). (b) \\(\\tfrac{46}{80} = \\tfrac{23}{40}\\)." } },

    // ── Mutually exclusive events ────
    { id: "y1pr1-018", topicRef: "y1pr1", topicTitle: "Probability 18", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["mutually exclusive", "definition"], questionText: "Events \\(A\\) and \\(B\\) are mutually exclusive with \\(P(A) = 0.3\\) and \\(P(B) = 0.45\\). Find \\(P(A \\cup B)\\) and \\(P(A \\cap B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Mutually exclusive means they cannot both occur.", workingLatex: "P(A \\cap B) = 0.", explanation: "" }, { stepNumber: 2, description: "Addition rule simplifies.", workingLatex: "P(A \\cup B) = P(A) + P(B) = 0.3 + 0.45 = 0.75.", explanation: "" }], finalAnswer: "\\(P(A \\cup B) = 0.75; \\ P(A \\cap B) = 0\\)." } },
    { id: "y1pr1-019", topicRef: "y1pr1", topicTitle: "Probability 19", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["mutually exclusive", "die"], questionText: "A fair die is rolled. Let \\(A\\) be the event ‘score is 1 or 2' and \\(B\\) the event ‘score is 5 or 6'. Find \\(P(A \\cup B)\\) and state whether \\(A\\) and \\(B\\) are mutually exclusive.", workedSolution: { steps: [{ stepNumber: 1, description: "List outcomes.", workingLatex: "A = \\{1,2\\}, \\ B = \\{5,6\\}.", explanation: "" }, { stepNumber: 2, description: "No common outcomes.", workingLatex: "A \\cap B = \\emptyset \\Rightarrow \\text{mutually exclusive}.", explanation: "" }, { stepNumber: 3, description: "Sum probabilities.", workingLatex: "P(A \\cup B) = \\tfrac{2}{6} + \\tfrac{2}{6} = \\tfrac{4}{6} = \\tfrac{2}{3}.", explanation: "" }], finalAnswer: "\\(P(A \\cup B) = \\tfrac{4}{6} = \\tfrac{2}{3}\\); yes, \\(A\\) and \\(B\\) are mutually exclusive." } },
    { id: "y1pr1-020", topicRef: "y1pr1", topicTitle: "Probability 20", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["mutually exclusive", "test"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.4, \\ P(B) = 0.35, \\ P(A \\cup B) = 0.65\\). Determine whether \\(A\\) and \\(B\\) are mutually exclusive, justifying your answer.", workedSolution: { steps: [{ stepNumber: 1, description: "Apply addition rule.", workingLatex: "0.65 = 0.4 + 0.35 - P(A \\cap B).", explanation: "" }, { stepNumber: 2, description: "Solve.", workingLatex: "P(A \\cap B) = 0.75 - 0.65 = 0.10.", explanation: "" }, { stepNumber: 3, description: "Conclude.", workingLatex: "P(A \\cap B) = 0.10 \\neq 0 \\Rightarrow \\text{not mutually exclusive.}", explanation: "" }], finalAnswer: "Not mutually exclusive: \\(P(A \\cap B) = 0.10 \\neq 0\\)." } },
    { id: "y1pr1-021", topicRef: "y1pr1", topicTitle: "Probability 21", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["mutually exclusive", "addition rule"], questionText: "A bag contains 12 red counters, 8 blue counters and 5 green counters. A counter is drawn at random. Find the probability it is (a) red or blue, (b) not green.", workedSolution: { steps: [{ stepNumber: 1, description: "Total counters.", workingLatex: "12 + 8 + 5 = 25.", explanation: "" }, { stepNumber: 2, description: "P(red or blue): mutually exclusive colours.", workingLatex: "\\tfrac{12}{25} + \\tfrac{8}{25} = \\tfrac{20}{25} = \\tfrac{4}{5}.", explanation: "" }, { stepNumber: 3, description: "P(not green) by complement.", workingLatex: "1 - \\tfrac{5}{25} = \\tfrac{20}{25} = \\tfrac{4}{5}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{20}{25} = \\tfrac{4}{5}\\). (b) \\(\\tfrac{20}{25} = \\tfrac{4}{5}\\)." } },

    // ── Independent events ────
    { id: "y1pr1-022", topicRef: "y1pr1", topicTitle: "Probability 22", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["independent events"], questionText: "Events \\(A\\) and \\(B\\) are independent with \\(P(A) = 0.6\\) and \\(P(B) = 0.4\\). Find \\(P(A \\cap B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use the multiplication rule for independent events.", workingLatex: "P(A \\cap B) = P(A) P(B).", explanation: "" }, { stepNumber: 2, description: "Compute.", workingLatex: "= 0.6 \\times 0.4 = 0.24.", explanation: "" }], finalAnswer: "\\(0.24\\)." } },
    { id: "y1pr1-023", topicRef: "y1pr1", topicTitle: "Probability 23", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["independent events", "coin"], questionText: "A fair coin is tossed twice. Find the probability of obtaining (a) two heads, (b) at least one head.", workedSolution: { steps: [{ stepNumber: 1, description: "Independent tosses.", workingLatex: "P(HH) = \\tfrac{1}{2} \\times \\tfrac{1}{2} = \\tfrac{1}{4}.", explanation: "" }, { stepNumber: 2, description: "Use complement.", workingLatex: "P(\\text{at least one H}) = 1 - P(TT) = 1 - \\tfrac{1}{4} = \\tfrac{3}{4}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{1}{4}\\). (b) \\(\\tfrac{3}{4}\\)." } },
    { id: "y1pr1-024", topicRef: "y1pr1", topicTitle: "Probability 24", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["independent events", "test"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.5, \\ P(B) = 0.4, \\ P(A \\cap B) = 0.2\\). Determine whether \\(A\\) and \\(B\\) are independent, justifying your answer.", workedSolution: { steps: [{ stepNumber: 1, description: "Compute the product.", workingLatex: "P(A) P(B) = 0.5 \\times 0.4 = 0.2.", explanation: "" }, { stepNumber: 2, description: "Compare with intersection.", workingLatex: "P(A \\cap B) = 0.2.", explanation: "" }, { stepNumber: 3, description: "Conclude.", workingLatex: "P(A) P(B) = P(A \\cap B) \\Rightarrow A, B \\text{ independent.}", explanation: "" }], finalAnswer: "Independent: \\(P(A) P(B) = 0.5 \\times 0.4 = 0.2 = P(A \\cap B)\\)." } },
    { id: "y1pr1-025", topicRef: "y1pr1", topicTitle: "Probability 25", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["independent events", "test"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.6, \\ P(B) = 0.3, \\ P(A \\cup B) = 0.78\\). Show whether \\(A\\) and \\(B\\) are independent.", workedSolution: { steps: [{ stepNumber: 1, description: "Find intersection from addition rule.", workingLatex: "0.78 = 0.6 + 0.3 - P(A \\cap B) \\Rightarrow P(A \\cap B) = 0.12.", explanation: "" }, { stepNumber: 2, description: "Compute product.", workingLatex: "P(A) P(B) = 0.6 \\times 0.3 = 0.18.", explanation: "" }, { stepNumber: 3, description: "Compare and conclude.", workingLatex: "0.12 \\neq 0.18 \\Rightarrow \\text{not independent.}", explanation: "" }], finalAnswer: "Not independent: \\(P(A \\cap B) = 0.12 \\neq 0.18 = P(A) P(B)\\)." } },
    { id: "y1pr1-026", topicRef: "y1pr1", topicTitle: "Probability 26", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["independent events", "algebra"], questionText: "Events \\(A\\) and \\(B\\) are independent with \\(P(A) = 0.4\\) and \\(P(A \\cup B) = 0.7\\). Find \\(P(B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Independence gives the intersection.", workingLatex: "P(A \\cap B) = P(A) P(B) = 0.4 P(B).", explanation: "" }, { stepNumber: 2, description: "Apply addition rule.", workingLatex: "0.7 = 0.4 + P(B) - 0.4 P(B).", explanation: "" }, { stepNumber: 3, description: "Simplify.", workingLatex: "0.7 - 0.4 = P(B)(1 - 0.4) \\Rightarrow 0.3 = 0.6 P(B).", explanation: "" }, { stepNumber: 4, description: "Solve.", workingLatex: "P(B) = \\tfrac{0.3}{0.6} = 0.5.", explanation: "" }], finalAnswer: "\\(P(B) = 0.5\\)." } },

    // ── Tree diagrams ────
    { id: "y1pr1-027", topicRef: "y1pr1", topicTitle: "Probability 27", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["tree diagram", "independent"], questionText: "The probability that a train arrives on time is 0.8. Two trains travel independently. Find the probability that (a) both arrive on time, (b) exactly one arrives on time.", workedSolution: { steps: [{ stepNumber: 1, description: "Both on time (multiplication rule).", workingLatex: "0.8 \\times 0.8 = 0.64.", explanation: "" }, { stepNumber: 2, description: "Exactly one on time.", workingLatex: "2 \\times 0.8 \\times 0.2 = 0.32.", explanation: "" }], finalAnswer: "(a) \\(0.64\\). (b) \\(0.32\\)." } },
    { id: "y1pr1-028", topicRef: "y1pr1", topicTitle: "Probability 28", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["tree diagram", "without replacement"], questionText: "A bag contains 4 red and 6 blue counters. Two counters are drawn at random without replacement. Find the probability that (a) both are red, (b) one is red and one is blue.", workedSolution: { steps: [{ stepNumber: 1, description: "P(both red).", workingLatex: "\\tfrac{4}{10} \\times \\tfrac{3}{9} = \\tfrac{12}{90} = \\tfrac{2}{15}.", explanation: "" }, { stepNumber: 2, description: "Two ways: RB or BR.", workingLatex: "\\tfrac{4}{10} \\times \\tfrac{6}{9} + \\tfrac{6}{10} \\times \\tfrac{4}{9} = \\tfrac{24}{90} + \\tfrac{24}{90} = \\tfrac{48}{90} = \\tfrac{8}{15}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{12}{90} = \\tfrac{2}{15}\\). (b) \\(\\tfrac{48}{90} = \\tfrac{8}{15}\\)." } },
    { id: "y1pr1-029", topicRef: "y1pr1", topicTitle: "Probability 29", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["tree diagram", "context"], questionText: "A factory has two machines. Machine A makes 60% of the output and 4% of its items are faulty. Machine B makes the rest, with 6% faulty. An item is chosen at random. Find (a) the probability it is faulty, (b) the probability it was made by Machine A and is not faulty.", workedSolution: { steps: [{ stepNumber: 1, description: "Tree branches: Machine then Faulty/Not.", workingLatex: "P(A,\\text{F}) = 0.6 \\times 0.04, \\ P(B,\\text{F}) = 0.4 \\times 0.06.", explanation: "" }, { stepNumber: 2, description: "Total P(F).", workingLatex: "0.024 + 0.024 = 0.048.", explanation: "" }, { stepNumber: 3, description: "P(A and not F).", workingLatex: "0.6 \\times 0.96 = 0.576.", explanation: "" }], finalAnswer: "(a) \\(0.048\\). (b) \\(0.576\\)." } },
    { id: "y1pr1-030", topicRef: "y1pr1", topicTitle: "Probability 30", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["tree diagram", "complement", "synoptic"], questionText: "Each morning Alice cycles to school with probability 0.7, otherwise she walks. If she cycles, she is late with probability 0.05; if she walks, she is late with probability 0.20. Find (a) the probability that, on a given morning, she is late, (b) the probability that on two independent mornings she is late on at least one of them.", workedSolution: { steps: [{ stepNumber: 1, description: "Tree: mode then late/on time.", workingLatex: "P(\\text{late}) = 0.7 \\times 0.05 + 0.3 \\times 0.20.", explanation: "" }, { stepNumber: 2, description: "Compute.", workingLatex: "= 0.035 + 0.060 = 0.095.", explanation: "" }, { stepNumber: 3, description: "Two independent mornings: complement.", workingLatex: "P(\\text{at least one late}) = 1 - (1 - 0.095)^2 = 1 - 0.905^2.", explanation: "" }, { stepNumber: 4, description: "Evaluate.", workingLatex: "0.905^2 = 0.819025; \\quad 1 - 0.819025 = 0.180975.", explanation: "" }], finalAnswer: "(a) \\(0.095\\). (b) \\(0.180975\\)." } },
    // ── Sample space, listing outcomes, complement ────
    { id: "y1pr1-031", topicRef: "y1pr1", topicTitle: "Probability 31", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["sample space", "spinner"], questionText: "A fair eight-sided spinner has sides labelled 1 to 8. Find the probability of obtaining (a) a multiple of 3, (b) a number greater than 5.", workedSolution: { steps: [{ stepNumber: 1, description: "Sample space.", workingLatex: "S = \\{1,2,3,4,5,6,7,8\\}, \\ n(S)=8.", explanation: "" }, { stepNumber: 2, description: "Multiples of 3.", workingLatex: "\\{3,6\\} \\Rightarrow P = \\tfrac{2}{8} = \\tfrac{1}{4}.", explanation: "" }, { stepNumber: 3, description: "Greater than 5.", workingLatex: "\\{6,7,8\\} \\Rightarrow P = \\tfrac{3}{8}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{2}{8} = \\tfrac{1}{4}\\). (b) \\(\\tfrac{3}{8}\\)." } },
    { id: "y1pr1-032", topicRef: "y1pr1", topicTitle: "Probability 32", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["sample space", "two coins"], questionText: "Two fair coins are tossed. Find the probability of obtaining (a) two tails, (b) at least one head.", workedSolution: { steps: [{ stepNumber: 1, description: "Sample space.", workingLatex: "\\{HH, HT, TH, TT\\}, \\ n(S)=4.", explanation: "" }, { stepNumber: 2, description: "P(two tails).", workingLatex: "\\tfrac{1}{4}.", explanation: "" }, { stepNumber: 3, description: "P(at least one head) by complement.", workingLatex: "1 - \\tfrac{1}{4} = \\tfrac{3}{4}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{1}{4}\\). (b) \\(\\tfrac{3}{4}\\)." } },
    { id: "y1pr1-033", topicRef: "y1pr1", topicTitle: "Probability 33", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["sample space", "two dice", "difference"], questionText: "Two fair six-sided dice are rolled. Find the probability that the absolute difference between the scores is 2.", workedSolution: { steps: [{ stepNumber: 1, description: "Total outcomes.", workingLatex: "n(S)=36.", explanation: "" }, { stepNumber: 2, description: "List pairs with difference 2.", workingLatex: "(1,3),(3,1),(2,4),(4,2),(3,5),(5,3),(4,6),(6,4) \\Rightarrow 8 \\text{ outcomes.}", explanation: "" }, { stepNumber: 3, description: "Probability.", workingLatex: "\\tfrac{8}{36} = \\tfrac{2}{9}.", explanation: "" }], finalAnswer: "\\(\\tfrac{8}{36} = \\tfrac{2}{9}\\)." } },
    { id: "y1pr1-034", topicRef: "y1pr1", topicTitle: "Probability 34", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["sample space", "die and coin"], questionText: "A fair coin is tossed and a fair six-sided die is rolled. Find the probability of (a) a head and an even number, (b) a tail and a prime number.", workedSolution: { steps: [{ stepNumber: 1, description: "Total outcomes.", workingLatex: "n(S) = 2 \\times 6 = 12.", explanation: "" }, { stepNumber: 2, description: "Head and even.", workingLatex: "\\{H2,H4,H6\\} \\Rightarrow P = \\tfrac{3}{12} = \\tfrac{1}{4}.", explanation: "" }, { stepNumber: 3, description: "Tail and prime (primes on a die: 2, 3, 5).", workingLatex: "\\{T2,T3,T5\\} \\Rightarrow P = \\tfrac{3}{12} = \\tfrac{1}{4}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{3}{12} = \\tfrac{1}{4}\\). (b) \\(\\tfrac{3}{12} = \\tfrac{1}{4}\\)." } },
    { id: "y1pr1-035", topicRef: "y1pr1", topicTitle: "Probability 35", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["sample space", "two dice", "product"], questionText: "Two fair six-sided dice are rolled. Find the probability that the product of the scores is greater than 20.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify pairs with product > 20.", workingLatex: "(4,6),(6,4),(5,5),(5,6),(6,5),(6,6) \\Rightarrow 6 \\text{ outcomes.}", explanation: "" }, { stepNumber: 2, description: "Probability.", workingLatex: "P = \\tfrac{6}{36} = \\tfrac{1}{6}.", explanation: "" }], finalAnswer: "\\(\\tfrac{6}{36} = \\tfrac{1}{6}\\)." } },

    // ── Two-way tables ────
    { id: "y1pr1-036", topicRef: "y1pr1", topicTitle: "Probability 36", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["two-way table", "marginal"], questionText: "A class of 50 pupils is split by gender (Boy/Girl) and whether they wear glasses. 14 boys wear glasses, 12 girls wear glasses, and there are 28 boys in total. Find the probability that a randomly chosen pupil (a) is a girl who does not wear glasses, (b) does not wear glasses.", workedSolution: { steps: [{ stepNumber: 1, description: "Boys who don't wear glasses.", workingLatex: "28 - 14 = 14.", explanation: "" }, { stepNumber: 2, description: "Girls in total.", workingLatex: "50 - 28 = 22.", explanation: "" }, { stepNumber: 3, description: "Girls who don't wear glasses.", workingLatex: "22 - 12 = 10.", explanation: "" }, { stepNumber: 4, description: "P(girl without glasses).", workingLatex: "\\tfrac{10}{50} = \\tfrac{1}{5}.", explanation: "" }, { stepNumber: 5, description: "P(no glasses).", workingLatex: "\\tfrac{14 + 10}{50} = \\tfrac{24}{50} = \\tfrac{12}{25}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{10}{50} = \\tfrac{1}{5}\\). (b) \\(\\tfrac{24}{50} = \\tfrac{12}{25}\\)." } },
    { id: "y1pr1-037", topicRef: "y1pr1", topicTitle: "Probability 37", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["two-way table", "three categories"], questionText: "75 sixth-formers are studying one of Maths, History or Art. Of the 30 boys, 12 study Maths and 8 study History. Of the 45 girls, 18 study Maths and 15 study Art. A student is chosen at random. Find the probability that the student is (a) a boy studying Art, (b) studying History.", workedSolution: { steps: [{ stepNumber: 1, description: "Boys studying Art.", workingLatex: "30 - 12 - 8 = 10.", explanation: "" }, { stepNumber: 2, description: "Girls studying History.", workingLatex: "45 - 18 - 15 = 12.", explanation: "" }, { stepNumber: 3, description: "Total studying History.", workingLatex: "8 + 12 = 20.", explanation: "" }, { stepNumber: 4, description: "P(boy and Art).", workingLatex: "\\tfrac{10}{75} = \\tfrac{2}{15}.", explanation: "" }, { stepNumber: 5, description: "P(History).", workingLatex: "\\tfrac{20}{75} = \\tfrac{4}{15}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{10}{75} = \\tfrac{2}{15}\\). (b) \\(\\tfrac{20}{75} = \\tfrac{4}{15}\\)." } },
    { id: "y1pr1-038", topicRef: "y1pr1", topicTitle: "Probability 38", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["two-way table", "addition"], questionText: "A library records borrowers by age (Adult / Child) and by genre most recently borrowed (Fiction / Non-fiction). Of 120 borrowers: 70 are adults, and 80 borrowed Fiction. 50 adults borrowed Fiction. Find the probability that a randomly chosen borrower is (a) a child who borrowed Non-fiction, (b) an adult or borrowed Fiction.", workedSolution: { steps: [{ stepNumber: 1, description: "Adults who borrowed Non-fiction.", workingLatex: "70 - 50 = 20.", explanation: "" }, { stepNumber: 2, description: "Children who borrowed Fiction.", workingLatex: "80 - 50 = 30.", explanation: "" }, { stepNumber: 3, description: "Children who borrowed Non-fiction.", workingLatex: "(120 - 70) - 30 = 50 - 30 = 20.", explanation: "" }, { stepNumber: 4, description: "P(child and Non-fiction).", workingLatex: "\\tfrac{20}{120} = \\tfrac{1}{6}.", explanation: "" }, { stepNumber: 5, description: "P(adult or Fiction) by addition.", workingLatex: "\\tfrac{70 + 80 - 50}{120} = \\tfrac{100}{120} = \\tfrac{5}{6}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{20}{120} = \\tfrac{1}{6}\\). (b) \\(\\tfrac{100}{120} = \\tfrac{5}{6}\\)." } },
    { id: "y1pr1-039", topicRef: "y1pr1", topicTitle: "Probability 39", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["two-way table", "missing cell"], questionText: "A market researcher classifies 200 shoppers by store (X or Y) and by membership (Member / Non-member). 60% of shoppers were at store X, and a quarter of all shoppers are Members. 32 shoppers are Members at store Y. Find the probability that a randomly chosen shopper is (a) a Member at store X, (b) a Non-member.", workedSolution: { steps: [{ stepNumber: 1, description: "Shoppers at store X and store Y.", workingLatex: "\\text{Store X: } 0.6 \\times 200 = 120; \\ \\text{Store Y: } 80.", explanation: "" }, { stepNumber: 2, description: "Total members.", workingLatex: "0.25 \\times 200 = 50.", explanation: "" }, { stepNumber: 3, description: "Members at store X.", workingLatex: "50 - 32 = 18.", explanation: "" }, { stepNumber: 4, description: "P(Member at X).", workingLatex: "\\tfrac{18}{200} = 0.09.", explanation: "" }, { stepNumber: 5, description: "P(Non-member).", workingLatex: "\\tfrac{200 - 50}{200} = \\tfrac{150}{200} = 0.75.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{18}{200} = 0.09\\). (b) \\(\\tfrac{150}{200} = 0.75\\)." } },
    { id: "y1pr1-040", topicRef: "y1pr1", topicTitle: "Probability 40", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["two-way table", "algebra", "unknown"], questionText: "A two-way table classifies 150 people by smoker/non-smoker and by exercise (Yes/No). The number of smokers who do not exercise is twice the number of smokers who exercise. The number of non-smokers who exercise is three times the number of smokers who exercise. There are 30 non-smokers who do not exercise. Find the number of smokers in total.", workedSolution: { steps: [{ stepNumber: 1, description: "Let smokers who exercise = } x.", workingLatex: "\\text{Smokers no exercise} = 2x; \\ \\text{non-smokers who exercise} = 3x.", explanation: "" }, { stepNumber: 2, description: "Total equation.", workingLatex: "x + 2x + 3x + 30 = 150.", explanation: "" }, { stepNumber: 3, description: "Solve.", workingLatex: "6x = 120 \\Rightarrow x = 20.", explanation: "" }, { stepNumber: 4, description: "Total smokers.", workingLatex: "x + 2x = 3x = 60.", explanation: "" }], finalAnswer: "60." } },

    // ── Venn diagrams ────
    { id: "y1pr1-041", topicRef: "y1pr1", topicTitle: "Probability 41", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["Venn diagram"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.55, \\ P(B) = 0.30, \\ P(A \\cap B) = 0.18\\). Find \\(P(A \\cup B)\\) and \\(P(A' \\cap B')\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Apply addition rule.", workingLatex: "P(A \\cup B) = 0.55 + 0.30 - 0.18 = 0.67.", explanation: "" }, { stepNumber: 2, description: "Use complement.", workingLatex: "P(A' \\cap B') = 1 - 0.67 = 0.33.", explanation: "" }], finalAnswer: "\\(P(A \\cup B) = 0.67\\); \\(P(A' \\cap B') = 0.33\\)." } },
    { id: "y1pr1-042", topicRef: "y1pr1", topicTitle: "Probability 42", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["Venn diagram", "regions"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.4, \\ P(B) = 0.5, \\ P(A \\cap B) = 0.1\\). Find \\(P(A \\cap B')\\) and \\(P(A' \\cap B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "A only.", workingLatex: "P(A \\cap B') = P(A) - P(A \\cap B) = 0.4 - 0.1 = 0.3.", explanation: "" }, { stepNumber: 2, description: "B only.", workingLatex: "P(A' \\cap B) = P(B) - P(A \\cap B) = 0.5 - 0.1 = 0.4.", explanation: "" }], finalAnswer: "\\(P(A \\cap B') = 0.3; \\ P(A' \\cap B) = 0.4\\)." } },
    { id: "y1pr1-043", topicRef: "y1pr1", topicTitle: "Probability 43", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Venn diagram", "context"], questionText: "In a survey of 60 commuters: 35 read a newspaper (N), 22 listen to a podcast (P), and 14 do both. Find the probability that a randomly chosen commuter (a) does at least one of these, (b) does neither.", workedSolution: { steps: [{ stepNumber: 1, description: "Newspaper only.", workingLatex: "35 - 14 = 21.", explanation: "" }, { stepNumber: 2, description: "Podcast only.", workingLatex: "22 - 14 = 8.", explanation: "" }, { stepNumber: 3, description: "At least one.", workingLatex: "21 + 14 + 8 = 43 \\Rightarrow P = \\tfrac{43}{60}.", explanation: "" }, { stepNumber: 4, description: "Neither by complement.", workingLatex: "60 - 43 = 17 \\Rightarrow P = \\tfrac{17}{60}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{43}{60}\\). (b) \\(\\tfrac{17}{60}\\)." } },
    { id: "y1pr1-044", topicRef: "y1pr1", topicTitle: "Probability 44", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Venn diagram", "exactly one"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.45, \\ P(B) = 0.35, \\ P(A \\cap B) = 0.12\\). Find the probability that exactly one of \\(A, B\\) occurs.", workedSolution: { steps: [{ stepNumber: 1, description: "Exactly one = (A only) + (B only).", workingLatex: "P(\\text{only }A) + P(\\text{only }B).", explanation: "" }, { stepNumber: 2, description: "A only and B only.", workingLatex: "P(A) - P(A \\cap B) = 0.33; \\ P(B) - P(A \\cap B) = 0.23.", explanation: "" }, { stepNumber: 3, description: "Sum.", workingLatex: "0.33 + 0.23 = 0.56.", explanation: "" }], finalAnswer: "\\(0.56\\)." } },
    { id: "y1pr1-045", topicRef: "y1pr1", topicTitle: "Probability 45", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Venn diagram", "three sets"], questionText: "Of 80 students surveyed about sports clubs: 30 play Football (F), 28 play Hockey (H), 25 play Cricket (C). 12 play F and H, 10 play F and C, 9 play H and C, and 4 play all three. Find the number of students who play at least one of these sports.", workedSolution: { steps: [{ stepNumber: 1, description: "Inclusion–exclusion.", workingLatex: "|F \\cup H \\cup C| = 30 + 28 + 25 - 12 - 10 - 9 + 4.", explanation: "" }, { stepNumber: 2, description: "Compute.", workingLatex: "= 83 - 31 + 4 = 56.", explanation: "" }], finalAnswer: "56." } },
    { id: "y1pr1-046", topicRef: "y1pr1", topicTitle: "Probability 46", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["Venn diagram", "algebra"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 2x, \\ P(B) = x, \\ P(A \\cap B) = 0.05, \\ P(A \\cup B) = 0.55\\). Find \\(x\\) and hence \\(P(A)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Apply addition rule.", workingLatex: "0.55 = 2x + x - 0.05.", explanation: "" }, { stepNumber: 2, description: "Solve.", workingLatex: "3x = 0.60 \\Rightarrow x = 0.20.", explanation: "" }, { stepNumber: 3, description: "P(A).", workingLatex: "P(A) = 2x = 0.40.", explanation: "" }], finalAnswer: "\\(x = 0.20\\); \\(P(A) = 0.40\\)." } },
    { id: "y1pr1-047", topicRef: "y1pr1", topicTitle: "Probability 47", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["Venn diagram", "three sets", "exactly two"], questionText: "100 readers were surveyed about three magazines, A, B and C. The numbers reading exactly two of the three magazines were: A and B only, 8; A and C only, 6; B and C only, 5. The number reading all three was 4. Of those reading at least one magazine, 50 read A, 40 read B and 35 read C. Find the number reading none of the magazines.", workedSolution: { steps: [{ stepNumber: 1, description: "Pairwise intersections.", workingLatex: "|A \\cap B| = 8 + 4 = 12, \\ |A \\cap C| = 6 + 4 = 10, \\ |B \\cap C| = 5 + 4 = 9.", explanation: "" }, { stepNumber: 2, description: "Inclusion–exclusion.", workingLatex: "|A \\cup B \\cup C| = 50 + 40 + 35 - 12 - 10 - 9 + 4.", explanation: "" }, { stepNumber: 3, description: "Compute.", workingLatex: "125 - 31 + 4 = 98.", explanation: "" }, { stepNumber: 4, description: "None.", workingLatex: "100 - 98 = 2.", explanation: "" }], finalAnswer: "2." } },

    // ── Mutually exclusive events ────
    { id: "y1pr1-048", topicRef: "y1pr1", topicTitle: "Probability 48", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["mutually exclusive"], questionText: "Events \\(A\\) and \\(B\\) are mutually exclusive with \\(P(A) = 0.25\\) and \\(P(A \\cup B) = 0.6\\). Find \\(P(B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For mutually exclusive events, intersection is 0.", workingLatex: "P(A \\cup B) = P(A) + P(B).", explanation: "" }, { stepNumber: 2, description: "Solve for P(B).", workingLatex: "P(B) = 0.6 - 0.25 = 0.35.", explanation: "" }], finalAnswer: "\\(0.35\\)." } },
    { id: "y1pr1-049", topicRef: "y1pr1", topicTitle: "Probability 49", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["mutually exclusive", "context"], questionText: "A bag of marbles contains red, blue, green and yellow marbles. The probabilities of drawing red, blue and green are 0.4, 0.25 and 0.15 respectively. Find the probability of drawing (a) red or green, (b) yellow.", workedSolution: { steps: [{ stepNumber: 1, description: "Different colours are mutually exclusive.", workingLatex: "P(R \\cup G) = 0.4 + 0.15 = 0.55.", explanation: "" }, { stepNumber: 2, description: "Probabilities sum to 1.", workingLatex: "P(Y) = 1 - (0.4 + 0.25 + 0.15) = 0.20.", explanation: "" }], finalAnswer: "(a) \\(0.55\\). (b) \\(0.20\\)." } },
    { id: "y1pr1-050", topicRef: "y1pr1", topicTitle: "Probability 50", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["mutually exclusive", "test"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.3, \\ P(B) = 0.45, \\ P(A \\cap B) = 0.0\\). State whether \\(A\\) and \\(B\\) are (i) mutually exclusive, (ii) independent, justifying each answer.", workedSolution: { steps: [{ stepNumber: 1, description: "Check mutually exclusive.", workingLatex: "P(A \\cap B) = 0 \\Rightarrow \\text{mutually exclusive.}", explanation: "" }, { stepNumber: 2, description: "Check independence.", workingLatex: "P(A) P(B) = 0.3 \\times 0.45 = 0.135.", explanation: "" }, { stepNumber: 3, description: "Conclude.", workingLatex: "0.135 \\neq 0 \\Rightarrow \\text{not independent.}", explanation: "" }], finalAnswer: "(i) Mutually exclusive: \\(P(A \\cap B) = 0\\). (ii) Not independent: \\(P(A) P(B) = 0.135 \\neq 0 = P(A \\cap B)\\)." } },
    { id: "y1pr1-051", topicRef: "y1pr1", topicTitle: "Probability 51", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["mutually exclusive", "addition rule", "context"], questionText: "A box contains 50 raffle tickets numbered 1 to 50. One ticket is drawn at random. Find the probability that the number drawn is (a) a multiple of 5 or a multiple of 7, (b) a prime number less than 20.", workedSolution: { steps: [{ stepNumber: 1, description: "Multiples of 5 in 1–50.", workingLatex: "\\{5,10,\\ldots,50\\} \\Rightarrow 10 \\text{ values.}", explanation: "" }, { stepNumber: 2, description: "Multiples of 7 in 1–50.", workingLatex: "\\{7,14,21,28,35,42,49\\} \\Rightarrow 7 \\text{ values.}", explanation: "" }, { stepNumber: 3, description: "Multiples of 35 (intersection).", workingLatex: "\\{35\\} \\Rightarrow 1 \\text{ value.}", explanation: "" }, { stepNumber: 4, description: "Use addition with overlap.", workingLatex: "P = \\tfrac{10 + 7 - 1}{50} = \\tfrac{16}{50} = \\tfrac{8}{25}.", explanation: "" }, { stepNumber: 5, description: "Primes < 20 in 1–50.", workingLatex: "\\{2,3,5,7,11,13,17,19\\} \\Rightarrow 8 \\text{ values}, \\ P = \\tfrac{8}{50} = \\tfrac{4}{25}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{16}{50} = \\tfrac{8}{25}\\). (b) \\(\\tfrac{8}{50} = \\tfrac{4}{25}\\)." } },

    // ── Independent events ────
    { id: "y1pr1-052", topicRef: "y1pr1", topicTitle: "Probability 52", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["independent"], questionText: "Events \\(A\\) and \\(B\\) are independent with \\(P(A) = 0.7\\) and \\(P(B) = 0.2\\). Find \\(P(A \\cup B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Independence gives intersection.", workingLatex: "P(A \\cap B) = 0.7 \\times 0.2 = 0.14.", explanation: "" }, { stepNumber: 2, description: "Apply addition rule.", workingLatex: "P(A \\cup B) = 0.7 + 0.2 - 0.14 = 0.76.", explanation: "" }], finalAnswer: "\\(0.76\\)." } },
    { id: "y1pr1-053", topicRef: "y1pr1", topicTitle: "Probability 53", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["independent", "complement"], questionText: "The probability that a particular alarm sounds when triggered is 0.95. Two alarms are triggered independently. Find the probability that at least one alarm sounds.", workedSolution: { steps: [{ stepNumber: 1, description: "Use complement.", workingLatex: "P(\\text{neither sounds}) = 0.05 \\times 0.05 = 0.0025.", explanation: "" }, { stepNumber: 2, description: "At least one sounds.", workingLatex: "1 - 0.0025 = 0.9975.", explanation: "" }], finalAnswer: "\\(0.9975\\)." } },
    { id: "y1pr1-054", topicRef: "y1pr1", topicTitle: "Probability 54", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["independent", "test"], questionText: "Events \\(A\\) and \\(B\\) satisfy \\(P(A) = 0.4, \\ P(B) = 0.25, \\ P(A \\cup B) = 0.55\\). Determine whether \\(A\\) and \\(B\\) are independent.", workedSolution: { steps: [{ stepNumber: 1, description: "Find intersection.", workingLatex: "0.55 = 0.4 + 0.25 - P(A \\cap B) \\Rightarrow P(A \\cap B) = 0.10.", explanation: "" }, { stepNumber: 2, description: "Compute product.", workingLatex: "P(A) P(B) = 0.4 \\times 0.25 = 0.10.", explanation: "" }, { stepNumber: 3, description: "Conclude.", workingLatex: "0.10 = 0.10 \\Rightarrow \\text{independent.}", explanation: "" }], finalAnswer: "Independent: \\(P(A \\cap B) = 0.10 = P(A)P(B)\\)." } },
    { id: "y1pr1-055", topicRef: "y1pr1", topicTitle: "Probability 55", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["independent", "complement", "at least one"], questionText: "The probability that a randomly chosen lightbulb is faulty is 0.04. Five bulbs are tested independently. Find, to 4 d.p., the probability that (a) none are faulty, (b) at least one is faulty.", workedSolution: { steps: [{ stepNumber: 1, description: "P(none faulty).", workingLatex: "0.96^5.", explanation: "" }, { stepNumber: 2, description: "Compute.", workingLatex: "0.96^5 = 0.81537\\ldots \\approx 0.8154.", explanation: "" }, { stepNumber: 3, description: "P(at least one faulty).", workingLatex: "1 - 0.8154 = 0.1846.", explanation: "" }], finalAnswer: "(a) \\(0.8154\\). (b) \\(0.1846\\)." } },
    { id: "y1pr1-056", topicRef: "y1pr1", topicTitle: "Probability 56", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["independent", "algebra"], questionText: "Events \\(A\\) and \\(B\\) are independent with \\(P(A) = 0.3\\) and \\(P(A \\cup B) = 0.58\\). Find \\(P(B)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use independence.", workingLatex: "P(A \\cap B) = 0.3 P(B).", explanation: "" }, { stepNumber: 2, description: "Apply addition rule.", workingLatex: "0.58 = 0.3 + P(B) - 0.3 P(B).", explanation: "" }, { stepNumber: 3, description: "Simplify.", workingLatex: "0.28 = 0.7 P(B).", explanation: "" }, { stepNumber: 4, description: "Solve.", workingLatex: "P(B) = \\tfrac{0.28}{0.7} = 0.4.", explanation: "" }], finalAnswer: "\\(P(B) = 0.4\\)." } },

    // ── Tree diagrams ────
    { id: "y1pr1-057", topicRef: "y1pr1", topicTitle: "Probability 57", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["tree diagram", "with replacement"], questionText: "A bag contains 5 red and 3 blue counters. A counter is drawn, its colour noted, and replaced; then a second counter is drawn. Find the probability that both are red.", workedSolution: { steps: [{ stepNumber: 1, description: "Independent draws (with replacement).", workingLatex: "P(R) = \\tfrac{5}{8} \\text{ each time.}", explanation: "" }, { stepNumber: 2, description: "Multiply.", workingLatex: "P(RR) = \\tfrac{5}{8} \\times \\tfrac{5}{8} = \\tfrac{25}{64}.", explanation: "" }], finalAnswer: "\\(\\tfrac{25}{64}\\)." } },
    { id: "y1pr1-058", topicRef: "y1pr1", topicTitle: "Probability 58", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["tree diagram", "without replacement"], questionText: "A bag contains 6 white and 4 black balls. Two balls are drawn without replacement. Find the probability that (a) both are the same colour, (b) the balls are of different colours.", workedSolution: { steps: [{ stepNumber: 1, description: "Both white.", workingLatex: "\\tfrac{6}{10} \\times \\tfrac{5}{9} = \\tfrac{30}{90}.", explanation: "" }, { stepNumber: 2, description: "Both black.", workingLatex: "\\tfrac{4}{10} \\times \\tfrac{3}{9} = \\tfrac{12}{90}.", explanation: "" }, { stepNumber: 3, description: "Same colour.", workingLatex: "\\tfrac{30 + 12}{90} = \\tfrac{42}{90} = \\tfrac{7}{15}.", explanation: "" }, { stepNumber: 4, description: "Different colour by complement.", workingLatex: "1 - \\tfrac{7}{15} = \\tfrac{8}{15}.", explanation: "" }], finalAnswer: "(a) \\(\\tfrac{42}{90} = \\tfrac{7}{15}\\). (b) \\(\\tfrac{48}{90} = \\tfrac{8}{15}\\)." } },
    { id: "y1pr1-059", topicRef: "y1pr1", topicTitle: "Probability 59", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["tree diagram", "context"], questionText: "A diagnostic test gives a positive result for 98% of people who have a particular condition, and a positive result for 3% of people who do not have the condition. In a population, 5% of people have the condition. A randomly chosen person is tested. Find (a) the probability the test is positive, (b) the probability the person has the condition and tests negative.", workedSolution: { steps: [{ stepNumber: 1, description: "Tree branches: condition then test.", workingLatex: "P(\\text{C, +}) = 0.05 \\times 0.98; \\ P(\\text{not C, +}) = 0.95 \\times 0.03.", explanation: "" }, { stepNumber: 2, description: "Total P(positive).", workingLatex: "0.049 + 0.0285 = 0.0775.", explanation: "" }, { stepNumber: 3, description: "P(C and negative).", workingLatex: "0.05 \\times 0.02 = 0.001.", explanation: "" }], finalAnswer: "(a) \\(0.0775\\). (b) \\(0.001\\)." } },
    { id: "y1pr1-060", topicRef: "y1pr1", topicTitle: "Probability 60", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["tree diagram", "complement", "synoptic"], questionText: "Each day Sam revises with probability 0.8. If he revises, he passes a daily test with probability 0.9; if he does not revise, he passes with probability 0.4. Tests on different days are independent. Find (a) the probability he passes a single day's test, (b) the probability he passes both tests on two consecutive days.", workedSolution: { steps: [{ stepNumber: 1, description: "P(pass one day).", workingLatex: "0.8 \\times 0.9 + 0.2 \\times 0.4 = 0.72 + 0.08 = 0.80.", explanation: "" }, { stepNumber: 2, description: "Independent days.", workingLatex: "P(\\text{pass both}) = 0.80 \\times 0.80 = 0.64.", explanation: "" }], finalAnswer: "(a) \\(0.80\\). (b) \\(0.64\\)." } },
];


